import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';
import { ConfigProvider } from "./ConfigContext";

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <ConfigProvider config = {config}>
    <React.StrictMode>
      <App />
    </React.StrictMode>
  </ConfigProvider>
);
